previewCss:
.darma-loader-darma-custom-585 {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
   height: 40px;
   aspect-ratio: .866;
   display: grid;
   background: conic-gradient(from -121deg at right,#0000, #BF1E62 1deg 60deg,#0000 61deg);
   animation: darma-loader-darma-custom-585-l12 2s infinite linear;
   transform-origin: 33% 50%;
}
.darma-loader-darma-custom-585:before, .darma-loader-darma-custom-585:after  {
  content: "";
   grid-area: 1/1;
   background: conic-gradient(from -121deg at right,#0000, #FFA588 1deg 60deg,#0000 61deg);
   transform-origin: inherit;
   animation: inherit;
}
.darma-loader-darma-custom-585:after  {
  background: conic-gradient(from -121deg at right,#0000, #027B7F 1deg 60deg,#0000 61deg);
   animation-duration: 3s;
}
@keyframes darma-loader-darma-custom-585-l12 {
  100% {transform: rotate(1turn)}
}

